import{_ as l,o as e,c as i,ag as t}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"最佳实践","description":"学会在安装完成之后，通过提示词、对话方式与显式规则，让 bamdra-openclaw-memory 的记忆切换与召回更无感、更自然。","frontmatter":{"title":"最佳实践","description":"学会在安装完成之后，通过提示词、对话方式与显式规则，让 bamdra-openclaw-memory 的记忆切换与召回更无感、更自然。"},"headers":[],"relativePath":"zh/guide/best-practices.md","filePath":"zh/guide/best-practices.md","lastUpdated":null}'),r={name:"zh/guide/best-practices.md"};function o(d,a,c,h,s,n){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h1><h2 id="安装完成之后-真正决定体验的是-怎么聊" tabindex="-1">安装完成之后，真正决定体验的是“怎么聊” <a class="header-anchor" href="#安装完成之后-真正决定体验的是-怎么聊" aria-label="Permalink to &quot;安装完成之后，真正决定体验的是“怎么聊”&quot;">​</a></h2><p>这个产品最好的状态，不是用户频繁显式操作记忆，而是用户几乎感觉不到上下文调度本身的存在，只会感受到对话更顺、切换更自然、恢复更及时。</p><h2 id="提示词应该怎么优化" tabindex="-1">提示词应该怎么优化 <a class="header-anchor" href="#提示词应该怎么优化" aria-label="Permalink to &quot;提示词应该怎么优化&quot;">​</a></h2><p>如果你希望插件的记忆切换和召回更丝滑，提示词里最好明确这些规则：</p><ul><li>用户说“记住这个”时，把它视为稳定事实保存信号</li><li>用户回到旧话题时，优先安静恢复上下文，而不是要求他重讲背景</li><li>某个事实可能已经存在时，先召回，再决定是否追问</li><li>除非用户明确要求，否则不要频繁解释内部记忆动作</li></ul><h2 id="可以用-skill-md-让引擎更聪明" tabindex="-1">可以用 SKILL.md 让引擎更聪明 <a class="header-anchor" href="#可以用-skill-md-让引擎更聪明" aria-label="Permalink to &quot;可以用 SKILL.md 让引擎更聪明&quot;">​</a></h2><p>除了基础提示词，你还可以通过 <code>SKILL.md</code> 给引擎增加一层更稳定的行为引导。</p><p>这层最适合承载的内容包括：</p><ul><li>什么情况下应该把一句话理解成“请记住”</li><li>什么情况下应该把一句话理解成“回到旧话题”</li><li>什么情况下应该判断为“这是一个新 topic”</li><li>在追问用户之前，什么时候应该先做召回</li></ul><p>这样做的价值在于，<code>SKILL.md</code> 可以把“如何理解用户意图”这件事写得更清楚，让引擎在真实对话中更容易做出正确判断。</p><h2 id="更自然的聊天方式是什么样" tabindex="-1">更自然的聊天方式是什么样 <a class="header-anchor" href="#更自然的聊天方式是什么样" aria-label="Permalink to &quot;更自然的聊天方式是什么样&quot;">​</a></h2><p>更好的对话方式通常很简单：</p><ul><li>回到旧话题时，直接继续说，不必重铺完整背景</li><li>对长期偏好、长期约束、项目决策，用自然语言明确表达</li><li>切换到完全不同的话题时，用一句简短的话说明“换个话题”或“回到刚才那个”</li></ul><h2 id="无感切换的理想体验" tabindex="-1">无感切换的理想体验 <a class="header-anchor" href="#无感切换的理想体验" aria-label="Permalink to &quot;无感切换的理想体验&quot;">​</a></h2><p>理想状态下，用户不会觉得自己在操作一个记忆系统，而是会自然感受到：</p><ul><li>旧话题能顺滑接回</li><li>稳定事实会在合适的时候自动被重新利用</li><li>中途插入的新任务不会污染原本的话题主线</li></ul><h2 id="显式语言调用的理想规则" tabindex="-1">显式语言调用的理想规则 <a class="header-anchor" href="#显式语言调用的理想规则" aria-label="Permalink to &quot;显式语言调用的理想规则&quot;">​</a></h2><p>显式规则应该足够清晰，但又不应该把对话变成命令行：</p><ul><li>当用户说“记住这个”时，优先保存稳定事实</li><li>当用户说“回到刚才那个话题”时，优先恢复旧 topic</li><li>当用户说“这是新话题”时，避免把旧上下文继续带进来</li><li>当用户问“你还记得吗”时，先召回，再决定是否追问</li></ul><h2 id="为什么双线保障是核心" tabindex="-1">为什么双线保障是核心 <a class="header-anchor" href="#为什么双线保障是核心" aria-label="Permalink to &quot;为什么双线保障是核心&quot;">​</a></h2><p>这个产品最核心的上下文调度机制，就是规则 + 自然语言驱动的双线保障。</p><ul><li>规则负责兜底，让边界、显式指令和稳定事实处理更可靠</li><li>自然语言判断负责让体验更像真实对话，而不是固定命令的执行</li></ul><p>只有这两条线一起工作，切换与召回才能既稳又顺。</p>',24)])])}const m=l(r,[["render",o]]);export{u as __pageData,m as default};
